function cmdStatus() {
    const index = fs.readFileSync(INDEX_FILE, 'utf8');
    const files = index.split('\n').filter(l => l.length > 0);
    console.log('Staged files:');
    if (files.length === 0) {
        console.log('(none)');
    } else {
        for (const f of files) {
            console.log(f);
        }
    }
}

function parseCommit(content) {
    const lines = content.split('\n');
    let parent = '';
    let timestamp = '';
    let message = '';
    const files = {};
    let inFiles = false;
    for (const line of lines) {
        if (line.startsWith('parent: ')) { parent = line.slice(8); inFiles = false; }
        else if (line.startsWith('timestamp: ')) { timestamp = line.slice(11); inFiles = false; }
        else if (line.startsWith('message: ')) { message = line.slice(9); inFiles = false; }
        else if (line === 'files:') { inFiles = true; }
        else if (inFiles && line.length > 0) {
            const idx = line.lastIndexOf(' ');
            files[line.slice(0, idx)] = line.slice(idx + 1);
        }
    }
    return { parent, timestamp, message, files };
}

function cmdDiff(hash1, hash2) {
    const p1 = path.join(COMMITS_DIR, hash1);
    const p2 = path.join(COMMITS_DIR, hash2);
    if (!fs.existsSync(p1) || !fs.existsSync(p2)) {
        console.log('Invalid commit');
        process.exit(1);
    }
    const c1 = parseCommit(fs.readFileSync(p1, 'utf8'));
    const c2 = parseCommit(fs.readFileSync(p2, 'utf8'));
    const allFiles = new Set([...Object.keys(c1.files), ...Object.keys(c2.files)]);
    const sorted = Array.from(allFiles).sort();
    for (const f of sorted) {
        if (!(f in c1.files) && f in c2.files) console.log(`Added: ${f}`);
        else if (f in c1.files && !(f in c2.files)) console.log(`Removed: ${f}`);
        else if (c1.files[f] !== c2.files[f]) console.log(`Modified: ${f}`);
    }
}

function cmdCheckout(commitHash) {
    const commitPath = path.join(COMMITS_DIR, commitHash);
    if (!fs.existsSync(commitPath)) {
        console.log('Invalid commit');
        process.exit(1);
    }
    const commit = parseCommit(fs.readFileSync(commitPath, 'utf8'));
    for (const [filename, blobHash] of Object.entries(commit.files)) {
        const content = fs.readFileSync(path.join(OBJECTS_DIR, blobHash));
        fs.writeFileSync(filename, content);
    }
    fs.writeFileSync(HEAD_FILE, commitHash);
    fs.writeFileSync(INDEX_FILE, '');
    console.log(`Checked out ${commitHash}`);
}

function cmdReset(commitHash) {
    const commitPath = path.join(COMMITS_DIR, commitHash);
    if (!fs.existsSync(commitPath)) {
        console.log('Invalid commit');
        process.exit(1);
    }
    fs.writeFileSync(HEAD_FILE, commitHash);
    fs.writeFileSync(INDEX_FILE, '');
    console.log(`Reset to ${commitHash}`);
}

function cmdRm(filename) {
    const index = fs.readFileSync(INDEX_FILE, 'utf8');
    const lines = index.split('\n').filter(l => l.length > 0);
    if (!lines.includes(filename)) {
        console.log('File not in index');
        process.exit(1);
    }
    const newLines = lines.filter(l => l !== filename);
    fs.writeFileSync(INDEX_FILE, newLines.length > 0 ? newLines.join('\n') + '\n' : '');
}

function cmdShow(commitHash) {
    const commitPath = path.join(COMMITS_DIR, commitHash);
    if (!fs.existsSync(commitPath)) {
        console.log('Invalid commit');
        process.exit(1);
    }
    const commit = parseCommit(fs.readFileSync(commitPath, 'utf8'));
    console.log(`commit ${commitHash}`);
    console.log(`Date: ${commit.timestamp}`);
    console.log(`Message: ${commit.message}`);
    console.log('Files:');
    const sorted = Object.keys(commit.files).sort();
    for (const f of sorted) {
        console.log(`  ${f} ${commit.files[f]}`);
    }
}

